{
  "case_summary": "55岁女性，腹腔镜胆囊切除术后6小时，生命体征平稳。当前主要问题为中度术后疼痛（5分）、轻微恶心、留置腹腔引流管，且尚未下床活动，对术后早期活动存在认知误区（担心影响切口）。",
  "nursing_problems": [
    {
      "problem": "急性疼痛",
      "evidence": "患者主诉疼痛，疼痛评分5分，处于腹腔镜胆囊切除术后6小时",
      "priority": "高"
    },
    {
      "problem": "躯体活动障碍/活动无耐力",
      "evidence": "术后6小时尚未下床，患者担心活动会影响切口",
      "priority": "中"
    },
    {
      "problem": "潜在并发症：出血/胆漏/感染",
      "evidence": "留置腹腔引流管，处于术后早期",
      "priority": "高"
    },
    {
      "problem": "恶心",
      "evidence": "患者主诉轻微恶心，与术后麻醉反应及手术刺激有关",
      "priority": "低"
    }
  ],
  "goals": [
    {
      "timeframe": "术后24小时内",
      "target": "患者疼痛评分降至3分或以下，能够耐受日常活动及翻身。"
    },
    {
      "timeframe": "术后24小时内",
      "target": "患者能在协助下首次下床活动，并正确复述早期活动的益处，消除对切口裂开的顾虑。"
    },
    {
      "timeframe": "术后24小时内",
      "target": "腹腔引流管保持通畅，引流液颜色、性质、量在正常范围内，无出血或胆漏征象。"
    },
    {
      "timeframe": "术后12小时内",
      "target": "患者恶心症状缓解或消失，未发生呕吐及误吸。"
    }
  ],
  "interventions": [
    {
      "action": "评估疼痛性质、部位及评分，遵医嘱给予镇痛药物，或指导使用非药物镇痛措施（如深呼吸、放松技巧、舒适体位）。",
      "rationale": "有效控制疼痛有助于患者早期下床活动和呼吸功能恢复，提高舒适度。",
      "frequency_or_timing": "每4小时评估一次，或按需评估及干预。"
    },
    {
      "action": "向患者解释腹腔镜手术切口小、愈合快，适当活动不会导致切口裂开；协助并指导患者进行床上翻身、四肢活动，逐步过渡到床边坐起及下床行走。",
      "rationale": "纠正患者错误认知能提高依从性；早期活动可预防深静脉血栓、促进胃肠功能恢复。",
      "frequency_or_timing": "术后6-8小时开始协助床上活动，术后24小时内协助首次下床。"
    },
    {
      "action": "妥善固定腹腔引流管，保持引流通畅，避免折叠受压；观察并记录引流液的颜色、性质和量。",
      "rationale": "保持引流有效，以便及时发现术后出血、胆漏等并发症。",
      "frequency_or_timing": "每小时观察记录一次，病情平稳后每4小时一次。"
    },
    {
      "action": "评估恶心程度，指导患者缓慢深呼吸，保持口腔清洁；若恶心加重，遵医嘱给予止吐药物。",
      "rationale": "缓解术后恶心呕吐，提高患者舒适度，防止呕吐物误吸。",
      "frequency_or_timing": "持续评估，按需干预。"
    },
    {
      "action": "观察腹部切口敷料有无渗血、渗液，评估腹部体征（有无压痛、反跳痛、肌紧张）。",
      "rationale": "监测切口愈合情况及腹腔内情况，早期发现异常。",
      "frequency_or_timing": "每4小时评估一次。"
    }
  ],
  "observation_points": [
    "生命体征变化，特别是心率增快、血压下降等休克早期表现。",
    "腹部体征，有无剧烈腹痛、腹胀、腹膜刺激征。",
    "腹腔引流液的颜色、性质和量（若突然增多、呈鲜红色或呈黄绿色胆汁样需高度警惕）。",
    "切口敷料渗血、渗液情况及周围皮肤有无红肿。",
    "恶心呕吐情况及有无误吸风险。",
    "下肢有无肿胀、疼痛（警惕深静脉血栓形成）。"
  ],
  "escalation_criteria": [
    "突发剧烈腹痛，或腹部出现明显压痛、反跳痛、肌紧张。",
    "腹腔引流液突然增多，呈鲜红色（提示活动性出血）或呈黄绿色（提示胆漏）。",
    "生命体征异常：心率>100次/分或<60次/分，收缩压<90mmHg或较基础值下降>30mmHg，呼吸急促或血氧饱和度<95%。",
    "出现呕血、黑便或严重呕吐无法缓解。",
    "意识状态改变（如烦躁不安、嗜睡、谵妄）。",
    "切口大量渗血或裂开。",
    "疼痛评分持续>7分且常规镇痛措施无效。"
  ],
  "education_points": [
    "解释腹腔镜手术切口小、恢复快，术后早期下床活动不仅不会导致切口裂开，反而有助于预防血栓和促进肠胃功能恢复。",
    "指导正确的下床方法：先侧身，用手支撑床面缓慢坐起，确认无头晕后再在家属或护士协助下站立和行走。",
    "指导术后饮食过渡原则：从禁食到少量饮水，再到流质、半流质饮食，避免油腻和产气食物。",
    "指导有效咳嗽和深呼吸的方法，以预防肺部并发症。",
    "告知引流管的目的及注意事项，指导患者在翻身或活动时保护引流管，避免牵拉、折叠或脱出。"
  ],
  "safety_boundary": "本计划仅提供护理辅助建议，不能替代专业医疗诊断和治疗。所有护理措施的执行必须以医院现行规章制度、主管医生的具体医嘱以及责任护士的现场临床评估为准。如遇病情变化或红旗信号，请立即通知医生并启动应急预案。"
}

{
  "case_summary": "76岁男性，急性脑梗死第2天，右侧偏瘫（肌力2级），言语含糊，吞咽筛查未通过，留置鼻胃管。生命体征平稳，偶有咳嗽。家属有违规喂水润喉的意愿，患者存在极高的误吸及窒息风险。",
  "nursing_problems": [
