  ],
  "interventions": [
    {
      "action": "严格禁食禁水，拒绝家属喂水请求，改用湿棉签湿润口唇",
      "rationale": "吞咽筛查未通过，经口进食或水极易导致误吸、吸入性肺炎甚至窒息",
      "frequency_or_timing": "持续执行，按需使用湿棉签湿润口唇"
